192	// TestPromptIngressEvidencePrimitiveUsage is the AST gate that prevents
193	// future drift: every os.ReadFile / ioutil.ReadFile call inside the
194	// in-scope agent files whose argument names a "*PromptFile" symbol
195	// must either route through evidence (readPromptFileBounded /
196	// evidence.ReadFileClamped) or carry an //evidence:allow-unbounded
197	// annotation.
198	func TestPromptIngressEvidencePrimitiveUsage(t *testing.T) {
199		files := []string{
200			"runner.go",
201			"compare_adapter.go",
202			"service_run.go",
203			"execute_bead.go",
204		}
205	
206		for _, src := range files {
207			t.Run(src, func(t *testing.T) {
208				fset := token.NewFileSet()
209				file, err := parser.ParseFile(fset, src, nil, parser.ParseComments)
210				if err != nil {
211					t.Fatalf("parse %s: %v", src, err)
212				}
213	
214				hasAllow := func(node ast.Node) bool {
215					nodePos := fset.Position(node.Pos())
216					for _, cg := range file.Comments {
217						cgEnd := fset.Position(cg.End())
218						if cgEnd.Filename != nodePos.Filename {
219							continue
220						}
221						if cgEnd.Line >= nodePos.Line-3 && cgEnd.Line < nodePos.Line {
222							for _, c := range cg.List {
223								if strings.Contains(c.Text, "evidence:allow-unbounded") {
224									return true
225								}
226							}
227						}
228					}
229					return false
230				}
231	
232				var violations []string
233				ast.Inspect(file, func(n ast.Node) bool {
234					call, ok := n.(*ast.CallExpr)
235					if !ok {
236						return true
237					}
238					sel, ok := call.Fun.(*ast.SelectorExpr)
239					if !ok {
240						return true
241					}
242					ident, ok := sel.X.(*ast.Ident)
243					if !ok {
244						return true
245					}
246					readFile := (ident.Name == "os" && sel.Sel.Name == "ReadFile") ||
247						(ident.Name == "ioutil" && sel.Sel.Name == "ReadFile")
248					if !readFile || len(call.Args) == 0 {
249						return true
250					}
251					// Identify --prompt-file-style arguments. We match selector
252					// expressions whose right-hand side is "PromptFile" (e.g.
253					// opts.PromptFile, prompt.PromptFile). These are the symbols
254					// Stage D1 routes through readPromptFileBounded.
255					argSel, ok := call.Args[0].(*ast.SelectorExpr)
256					if !ok {
257						return true
258					}
259					if argSel.Sel == nil || argSel.Sel.Name != "PromptFile" {
260						return true
261					}
262					if !hasAllow(call) {
263						p := fset.Position(call.Pos())
264						violations = append(violations,
265							fmt.Sprintf("%s: os.ReadFile(<*.PromptFile>) at line %d not routed through evidence", src, p.Line))
266					}
267					return true
268				})
269	
270				if len(violations) > 0 {
271					t.Errorf("FEAT-022 §8 violation(s):\n  %s",
272						strings.Join(violations, "\n  "))
273				}
274			})
275		}
276	}
